Greedy insertion with rollback: try inserting each ship into every existing assign, compute marginal cost increase, pick the minimal positive feasible insertion, otherwise create a new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for jj := 0; jj < len(oris); jj++ {
        bestIdx := -1
        bestCostDelta := 1e308
        savedStates := make([]float64, dispatch.AssignsLen)
        savedCosts := make([]float64, dispatch.AssignsLen)

        // Evaluate all existing assigns
        for ii := 0; ii < dispatch.AssignsLen; ii++ {
            savedStates[ii] = dispatch.Assigns[ii].Cost
            if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
                dispatch.Assigns[ii].GenRoute()
                if dispatch.Assigns[ii].Cost >= 0 {
                    delta := dispatch.Assigns[ii].Cost - savedStates[ii]
                    if delta < bestCostDelta {
                        bestCostDelta = delta
                        bestIdx = ii
                    }
                    savedCosts[ii] = dispatch.Assigns[ii].Cost
                }
                dispatch.Assigns[ii].RemoveShip(total_ship + jj)
                dispatch.Assigns[ii].GenRoute()
            } else {
                savedCosts[ii] = -1
            }
        }

        // Try to insert into a new empty assign if allowed
        newAssignIdx := dispatch.AssignsLen
        if newAssignIdx < MAXASSIGNS {
            if dispatch.Assigns[newAssignIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
                dispatch.Assigns[newAssignIdx].GenRoute()
                if dispatch.Assigns[newAssignIdx].Cost >= 0 {
                    delta := dispatch.Assigns[newAssignIdx].Cost
                    if delta < bestCostDelta {
                        bestCostDelta = delta
                        bestIdx = newAssignIdx
                    }
                    dispatch.Assigns[newAssignIdx].RemoveShip(total_ship + jj)
                    dispatch.Assigns[newAssignIdx].GenRoute()
                } else {
                    dispatch.Assigns[newAssignIdx].RemoveShip(total_ship + jj)
                    dispatch.Assigns[newAssignIdx].GenRoute()
                }
            }
        }

        // Commit best insertion
        if bestIdx >= 0 {
            if bestIdx == dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
            dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
            dispatch.Assigns[bestIdx].GenRoute()
        } else {
            // Fallback: force into first available slot (new assign guaranteed at newAssignIdx < MAXASSIGNS)
            idx := dispatch.AssignsLen
            if idx >= MAXASSIGNS {
                idx = MAXASSIGNS - 1
            }
            dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
            dispatch.Assigns[idx].GenRoute()
            if dispatch.Assigns[idx].Cost >= 0 && idx == dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

